def edit_distance(a, b):
    """Return Levenshtein distance between a and b."""
    m, n = len(a), len(b)
    dist = [[0] * (n + 1) for _ in range(m + 1)]
    for i in range(m + 1):
        dist[i][0] = i
    for j in range(n + 1):
        dist[0][j] = j
    for i in range(1, m + 1):
        for j in range(1, n + 1):
            if a[i - 1] == b[j - 1]:
                cost = 0
            else:
                cost = 1
            diag = dist[i - 1][j - 1] + cost
            insert = dist[i - 1][j] + 1
            delete = dist[i][j - 1] + 1
            dist[i][j] = min(diag, insert, delete)
    return dist[m][n]

